import threading
import time
from lru_cache import LRUCache

# Thread-safety test
cache = LRUCache(100)
errors = []
results = []

def writerthread(thread_id):
    try:
        for i in range(100):
            cache.put(thread_id * 1000 + i, thread_id * 1000 + i)
            time.sleep(0.0001)
    except Exception as e:
        errors.append(e)

def readerthread(thread_id):
    try:
        for i in range(100):
            val = cache.get(thread_id * 1000 + i)
            results.append(val)
            time.sleep(0.0001)
    except Exception as e:
        errors.append(e)

# Create multiple reader and writer threads
threads = []
for i in range(3):
    threads.append(threading.Thread(target=writerthread, args=(i,)))
    threads.append(threading.Thread(target=readerthread, args=(i,)))

for t in threads:
    t.start()

for t in threads:
    t.join()

if errors:
    print(f'Thread safety errors: {errors}')
else:
    print('Thread safety test passed!')

# Check final size
print(f'Final size: {cache.size()}')
print(f'Cache capacity: {cache.capacity}')
"",
